const body = $json.body || $json;
const required = ['request_id', 'workflow_type', 'generated_by', 'client', 'brand', 'campaign', 'brief', 'options', 'video_script_types', 'safety'];
const missing = required.filter((key) => body[key] === undefined || body[key] === null);
const safety = body.safety || {};
const safetyOk = (body.workflow_type === 'video_scripts' || body.workflow_type === 'video_script')
  && body.owner_approval_required === true
  && body.generate_images === false
  && body.generate_videos === false
  && safety.no_auto_post === true
  && safety.no_auto_ads === true
  && safety.no_live_connectors === true
  && safety.no_image_generation === true
  && safety.no_video_generation === true
  && safety.no_secrets === true
  && safety.owner_approval_required === true;
if (missing.length || !safetyOk) {
  return [{ json: {
    ok: false,
    request_id: body.request_id || null,
    error: {
      code: missing.length ? 'INVALID_CONTRACT' : 'REJECTED_BY_SAFETY',
      message: missing.length ? `Missing required fields: ${missing.join(', ')}` : 'Safety flags rejected this request (video scripts are text/script only, no image or video generation).'
    },
    status: 'failed',
    owner_approval_required: true,
    safety
  }}];
}
return [{ json: body }];

const request = $json;
const channel = request.options?.channel || 'Facebook';
const goal = request.options?.goal || 'branding';
const brand = request.brand?.name || 'Brand';
const product = request.brief?.product_focus || request.brand?.hero_product || 'hero product';
const audience = request.brief?.target_audience || request.brand?.target_audience || 'core local audience';
const tone = request.brand?.tone_of_voice || 'warm, trustworthy';
const offer = request.brief?.offer || 'Assumption: feature the current campaign hero offer';
const specs = [
  { key: 'hook_first_3s',            title: 'Hook / First 3 Seconds Script',                  platform: 'Reels / TikTok', format: 'First 3 seconds (9:16 vertical)', objective: 'Stop the scroll in the first 3 seconds' },
  { key: 'short_form_script',        title: 'Short-Form Video Script (Reels/TikTok, 15-30s)', platform: 'Reels / TikTok', format: '15-30s vertical (9:16)',          objective: 'Deliver the core message in 15-30s' },
  { key: 'voiceover_caption_script', title: 'Voiceover / Caption Script',                     platform: 'Cross-channel',  format: 'Voiceover + on-screen captions', objective: 'Spoken + caption script that lands the message' },
  { key: 'shot_list_broll',          title: 'Shot List + B-roll Direction',                   platform: 'Production',     format: 'Shot list / B-roll plan',        objective: 'Give the shooter a clear, ordered shot list' },
  { key: 'editor_handoff_notes',     title: 'Editor Handoff Notes',                           platform: 'Internal',       format: 'Editor handoff document',        objective: 'Hand the cut to the editor cleanly' }
];
const items = specs.map((spec) => ({
  key: spec.key,
  title: spec.title,
  platform: spec.platform,
  format: spec.format,
  objective: spec.objective,
  target_audience: audience,
  script_body: `Scene-by-scene script for ${brand} featuring ${product}. ${spec.objective}. Offer: ${offer}.`,
  voiceover_text: `VO (tone: ${tone}): "${brand} - ${spec.objective}." On-screen captions mirror the VO.`,
  shot_direction: spec.key === 'shot_list_broll' ? `Ordered shots: hero ${product} close-up, prep/process B-roll, customer reaction, logo/CTA end card. Real footage only - no AI video.` : `Hold on the hero ${product}; keep the frame clean and on-brand. Real footage only - no AI video.`,
  cta: goal === 'sales' ? 'Inbox to order' : goal === 'lead' ? 'Leave your contact' : 'Follow for more',
  generated_by: 'n8n-ai-provider',
  workflow_type: 'video_scripts',
  content_type: 'video_script',
  status: 'pending_approval',
  owner_approval_required: true
}));
return [{ json: {
  ok: true,
  request_id: request.request_id,
  workflow_type: 'video_scripts',
  content_type: 'video_script',
  generated_by: 'n8n-ai-provider',
  owner_approval_required: true,
  status: 'pending_approval',
  job: {
    external_execution_id: $execution.id,
    item_count: items.length
  },
  items,
  safety: request.safety
}}];
